import { useState, useEffect, useRef } from "react";
import "@/App.css";
import { motion, useInView } from "framer-motion";
import { 
  ArrowRight, 
  Phone, 
  Check, 
  X, 
  Radar, 
  Camera, 
  Cpu, 
  Trophy,
  Star,
  Nfc,
  ShieldCheck,
  MapPin,
  TrendingUp,
  ChevronDown
} from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";

// Animation variants
const fadeInUp = {
  initial: { opacity: 0, y: 30 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] }
};

const staggerContainer = {
  animate: {
    transition: {
      staggerChildren: 0.1
    }
  }
};

// Carrousel de texte rotatif
const RotatingText = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [progress, setProgress] = useState(0);

  const texts = [
    { text: "Technologie NFC Sans Contact", icon: Nfc },
    { text: "Format Vidéo Certifié Google", icon: Camera },
    { text: "Déploiement Exclusif sur Tours", icon: MapPin },
    { text: "Optimisation 100% Parcours Client", icon: TrendingUp }
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % texts.length);
      setProgress(0);
    }, 4000);

    const progressInterval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) return 0;
        return prev + (100 / 40); // 4000ms / 100ms = 40 steps
      });
    }, 100);

    return () => {
      clearInterval(interval);
      clearInterval(progressInterval);
    };
  }, []);

  const CurrentIcon = texts[currentIndex].icon;

  return (
    <div className="flex flex-col items-center justify-center">
      <div className="h-6 flex items-center justify-center overflow-hidden mb-2">
        <motion.div
          key={currentIndex}
          initial={{ opacity: 0, x: 50 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: -50 }}
          transition={{ duration: 0.8, ease: "easeInOut" }}
          className="flex items-center gap-2"
        >
          <CurrentIcon className="w-4 h-4 text-[#1c3ff9]" />
          <p className="text-sm text-[#52525B] font-medium">
            {texts[currentIndex].text}
          </p>
        </motion.div>
      </div>

      {/* Barre de progression */}
      <div className="w-32 h-0.5 bg-gray-200 rounded-full overflow-hidden">
        <motion.div
          className="h-full bg-gradient-to-r from-[#1c3ff9] to-[#6366f1] rounded-full"
          style={{ width: `${progress}%` }}
          transition={{ duration: 0.1, ease: "linear" }}
        />
      </div>
    </div>
  );
};

